import{_ as a,z as o,m as l,ap as t}from"./chunks/framework.BtwXvyX_.js";const u=JSON.parse('{"title":"配置说明","description":"","frontmatter":{},"headers":[],"relativePath":"markdown/guide/config.md","filePath":"markdown/guide/config.md","lastUpdated":1774851650000}'),i={name:"markdown/guide/config.md"};function r(d,e,n,c,s,h){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="配置说明" tabindex="-1">配置说明 <a class="header-anchor" href="#配置说明" aria-label="Permalink to &quot;配置说明&quot;">​</a></h1><p>本页按当前源码中的 <code>src/config.ts</code> 说明插件配置项。</p><h2 id="基础设置" tabindex="-1">基础设置 <a class="header-anchor" href="#基础设置" aria-label="Permalink to &quot;基础设置&quot;">​</a></h2><h3 id="id" tabindex="-1">id <a class="header-anchor" href="#id" aria-label="Permalink to &quot;id&quot;">​</a></h3><ul><li>类型：<code>string</code></li><li>必填：是</li><li>说明：QQ 机器人 <code>AppID</code>，注意不是 QQ 号</li><li>前往 <a href="https://q.qq.com/qqbot/#/developer/developer-setting" target="_blank" rel="noreferrer">https://q.qq.com/qqbot/#/developer/developer-setting</a> 获取</li></ul><h3 id="secret" tabindex="-1">secret <a class="header-anchor" href="#secret" aria-label="Permalink to &quot;secret&quot;">​</a></h3><ul><li>类型：<code>string</code></li><li>必填：是</li><li>说明：QQ 机器人 <code>AppSecret</code></li><li>前往 <a href="https://q.qq.com/qqbot/#/developer/developer-setting" target="_blank" rel="noreferrer">https://q.qq.com/qqbot/#/developer/developer-setting</a> 获取</li></ul><h3 id="type" tabindex="-1">type <a class="header-anchor" href="#type" aria-label="Permalink to &quot;type&quot;">​</a></h3><ul><li>类型：<code>&#39;public&#39; | &#39;private&#39;</code></li><li>默认值：<code>private</code></li><li>说明：机器人类型</li><li>前往 <a href="https://q.qq.com/qqbot/#/developer/sandbox" target="_blank" rel="noreferrer">https://q.qq.com/qqbot/#/developer/sandbox</a> 可查看机器人类型</li></ul><h3 id="intents" tabindex="-1">intents <a class="header-anchor" href="#intents" aria-label="Permalink to &quot;intents&quot;">​</a></h3><ul><li>类型：<code>bitset</code></li><li>默认值：内置一组常用事件</li><li>说明：控制需要订阅哪些 QQ 事件</li></ul><p>如果你不确定，建议直接使用默认值。</p><h3 id="retrywhen" tabindex="-1">retryWhen <a class="header-anchor" href="#retrywhen" aria-label="Permalink to &quot;retryWhen&quot;">​</a></h3><ul><li>类型：<code>number[]</code></li><li>默认值：<code>[]</code></li><li>说明：发送消息遇到这些平台错误码时自动重试一次</li></ul><p>适合放一些你在实战里经常遇到、但重试有机会成功的错误码。</p><h3 id="protocol" tabindex="-1">protocol <a class="header-anchor" href="#protocol" aria-label="Permalink to &quot;protocol&quot;">​</a></h3><ul><li>类型：<code>&#39;websocket&#39; | &#39;webhook&#39;</code></li><li>默认值：<code>websocket</code></li><li>说明：选择连接协议</li></ul><h2 id="websocket-模式配置" tabindex="-1">WebSocket 模式配置 <a class="header-anchor" href="#websocket-模式配置" aria-label="Permalink to &quot;WebSocket 模式配置&quot;">​</a></h2><p>当 <code>protocol = websocket</code> 时，会额外启用 WebSocket 客户端配置。</p><h3 id="gatewayurl" tabindex="-1">gatewayUrl <a class="header-anchor" href="#gatewayurl" aria-label="Permalink to &quot;gatewayUrl&quot;">​</a></h3><ul><li>类型：<code>string</code></li><li>默认值：空</li><li>说明：覆盖 QQ 官方返回的 WebSocket 地址</li></ul><p>适合你通过反代、中转或抓包环境接入时使用。</p><h2 id="webhook-模式配置" tabindex="-1">Webhook 模式配置 <a class="header-anchor" href="#webhook-模式配置" aria-label="Permalink to &quot;Webhook 模式配置&quot;">​</a></h2><p>当 <code>protocol = webhook</code> 时，会启用下面的配置项。</p><h3 id="path" tabindex="-1">path <a class="header-anchor" href="#path" aria-label="Permalink to &quot;path&quot;">​</a></h3><ul><li>类型：<code>string</code></li><li>默认值：<code>/qq</code></li><li>说明：QQ 官方回调到 Koishi 的 HTTPS 路径</li></ul><p>例如你的 Koishi 对外地址是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>https://bot.example.com</span></span></code></pre></div><p>并且这里配置为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>/qq</span></span></code></pre></div><p>那么实际回调地址就是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>https://bot.example.com/qq</span></span></code></pre></div><p>需注意，webhook 接入必须要求有SSL证书，且校验时有延迟要求。</p><h2 id="进阶设置" tabindex="-1">进阶设置 <a class="header-anchor" href="#进阶设置" aria-label="Permalink to &quot;进阶设置&quot;">​</a></h2><h3 id="sandbox" tabindex="-1">sandbox <a class="header-anchor" href="#sandbox" aria-label="Permalink to &quot;sandbox&quot;">​</a></h3><ul><li>类型：<code>boolean</code></li><li>默认值：<code>false</code></li><li>说明：是否使用 QQ 沙箱地址</li></ul><p>开启后，仅响应沙箱环境的调用。</p><blockquote><p>不建议开启，这可能会导致你的提审不通过哦~</p></blockquote><h3 id="endpoint" tabindex="-1">endpoint <a class="header-anchor" href="#endpoint" aria-label="Permalink to &quot;endpoint&quot;">​</a></h3><ul><li>类型：<code>string</code></li><li>默认值：<code>https://api.sgroup.qq.com/</code></li><li>说明：覆盖 OpenAPI 根地址</li></ul><p>适合反代、中转服务或调试环境。</p><h3 id="manualacknowledge" tabindex="-1">manualAcknowledge <a class="header-anchor" href="#manualacknowledge" aria-label="Permalink to &quot;manualAcknowledge&quot;">​</a></h3><ul><li>类型：<code>boolean</code></li><li>默认值：<code>false</code></li><li>说明：是否手动响应互动回调</li></ul><p>默认情况下，按钮互动等回调会自动 ACK。</p><p>如果你想自己控制 ACK 时机，再打开这个选项。</p><h2 id="高级设置" tabindex="-1">高级设置 <a class="header-anchor" href="#高级设置" aria-label="Permalink to &quot;高级设置&quot;">​</a></h2><h3 id="autostreamtext" tabindex="-1">autoStreamText <a class="header-anchor" href="#autostreamtext" aria-label="Permalink to &quot;autoStreamText&quot;">​</a></h3><ul><li>类型：<code>boolean</code></li><li>默认值：<code>false</code></li><li>说明：是否把纯文本消息自动转成 QQ 原生 Markdown 流式首包</li></ul><p>这个开关只会处理“纯文本消息”。</p><p>包含图片、音频、视频、按钮、复杂元素的消息仍然会走原本的发送逻辑。</p><p>注意：</p><ul><li>这里的“自动流式”只会自动附加 <code>state = 1</code></li><li>适配器<strong>不会</strong>自动帮你发送 <code>state = 10</code></li><li>如果你要显式结束流式，需要自己传原始 <code>stream</code> 对象</li></ul><h3 id="loggerinfo" tabindex="-1">loggerinfo <a class="header-anchor" href="#loggerinfo" aria-label="Permalink to &quot;loggerinfo&quot;">​</a></h3><ul><li>类型：<code>boolean</code></li><li>默认值：<code>false</code></li><li>说明：调试模式</li></ul>',54)])])}const b=a(i,[["render",r]]);export{u as __pageData,b as default};
